INSERT INTO `wardrobe_items` (`id`, `userId`, `name`, `category`, `color`, `wuxing`, `material`, `occasion`, `imageUrl`, `note`, `createdAt`, `updatedAt`, `aiAnalysis`, `auraBoost`, `fromPhoto`) VALUES
(30001, 1, '深棕色木質手串', 'bracelet', '深棕色', '木', '木質', '休閒,約會', NULL, '這款深棕色的木質手串，在五行能量上屬於「木」。木代表著生長、活力、創新跟慈悲。如果你最近覺得有點卡關，或是需要多一點耐心跟毅力去完成某件事，戴上它會很有幫助喔！木的能量也能幫助你更有彈性，面對變化時可以更從容。而且木質本身就帶有大自然的氣息，能讓人感覺很放鬆、很接地氣。', '"2026-02-27T01:08:56.000Z"', '"2026-02-27T01:08:56.000Z"', '{"detectedColors":[{"part":"珠子","color":"深棕色","wuxing":"木"}],"energyExplanation":"這款深棕色的木質手串，在五行能量上屬於「木」。木代表著生長、活力、創新跟慈悲。如果你最近覺得有點卡關，或是需要多一點耐心跟毅力去完成某件事，戴上它會很有幫助喔！木的能量也能幫助你更有彈性，面對變化時可以更從容。而且木質本身就帶有大自然的氣息，能讓人感覺很放鬆、很接地氣。","auraBoost":7,"analyzedAt":"2026-02-26T20:08:56.921Z"}', 7, 1),
(60001, 540175, '米白色皮革錶帶智慧手錶', 'accessory', '米白', '金', '皮革、金屬、電子元件', '工作,休閒,約會', NULL, '這款智慧手錶的米白色皮革錶帶屬於『金』的能量，金代表著清晰、效率、收斂與貴氣。搭配玫瑰金屬的點綴，也帶有『火』的熱情與『金』的華麗。黑色的錶面則代表『水』的沉穩與內斂。整體來說，這款手錶能為你帶來精準、效率的能量，同時又不失溫和與時尚感。對於需要專注、提升工作效率，或是希望展現個人品味的朋友，是很不錯的選擇喔！', '"2026-02-27T17:58:47.000Z"', '"2026-02-27T18:02:11.000Z"', '{"detectedColors":[{"part":"錶帶","color":"米白","wuxing":"金"},{"part":"錶殼金屬","color":"玫瑰金","wuxing":"金"},{"part":"錶面","color":"黑","wuxing":"水"}],"energyExplanation":"這款智慧手錶的米白色皮革錶帶屬於『金』的能量，金代表著清晰、效率、收斂與貴氣。搭配玫瑰金屬的點綴，也帶有『火』的熱情與『金』的華麗。黑色的錶面則代表『水』的沉穩與內斂。整體來說，這款手錶能為你帶來精準、效率的能量，同時又不失溫和與時尚感。對於需要專注、提升工作效率，或是希望展現個人品味的朋友，是很不錯的選擇喔！","auraBoost":7,"analyzedAt":"2026-02-27T12:58:47.594Z"}', 7, 1),
(60002, 540175, '白色綁帶襯衫', 'upper', '白色', '金', '棉', '工作,休閒,約會', NULL, '這件白色綁帶襯衫，白色在五行中屬「金」。金代表著清晰、純潔、條理和效率。穿著金屬性的衣物，有助於提升你的專注力與判斷力，讓思緒更清晰，同時也能帶來一種專業且高雅的氣場。綁帶設計增添了一絲柔和與時尚感，讓金的能量不至於過於剛硬，反而能更好地融入日常穿搭，為你的整體形象加分喔！', '"2026-02-27T18:01:18.000Z"', '"2026-02-27T18:01:18.000Z"', '{"detectedColors":[{"part":"襯衫","color":"白色","wuxing":"金"},{"part":"下身衣物","color":"黑色","wuxing":"水"}],"energyExplanation":"這件白色綁帶襯衫，白色在五行中屬「金」。金代表著清晰、純潔、條理和效率。穿著金屬性的衣物，有助於提升你的專注力與判斷力，讓思緒更清晰，同時也能帶來一種專業且高雅的氣場。綁帶設計增添了一絲柔和與時尚感，讓金的能量不至於過於剛硬，反而能更好地融入日常穿搭，為你的整體形象加分喔！","auraBoost":7,"analyzedAt":"2026-02-27T13:01:18.921Z"}', 7, 1),
(60003, 1, '米白色皮革智慧手錶', 'accessory', '米白', '金', '皮革、金屬、電子', '工作,休閒,約會', NULL, '這款米白色皮革智慧手錶，主色調米白屬金，金代表著清晰、條理和效率，能幫助你思緒清晰，提升執行力。錶身的玫瑰金色澤帶有火的能量，能增添熱情與人緣。整體搭配起來，既有金的穩重，又有火的活力，對於需要提升專注力、同時又想保持良好人際關係的人來說，是個不錯的選擇喔！', '"2026-02-27T18:03:18.000Z"', '"2026-02-27T18:03:18.000Z"', '{"detectedColors":[{"part":"錶帶","color":"米白","wuxing":"金"},{"part":"錶扣與錶框","color":"玫瑰金","wuxing":"金"},{"part":"螢幕","color":"黑色","wuxing":"水"}],"energyExplanation":"這款米白色皮革智慧手錶，主色調米白屬金，金代表著清晰、條理和效率，能幫助你思緒清晰，提升執行力。錶身的玫瑰金色澤帶有火的能量，能增添熱情與人緣。整體搭配起來，既有金的穩重，又有火的活力，對於需要提升專注力、同時又想保持良好人際關係的人來說，是個不錯的選擇喔！","auraBoost":7,"analyzedAt":"2026-02-27T13:03:18.749Z"}', 7, 1),
(90001, 1, '多色瑪瑙手串', 'bracelet', '棕色與橘紅色', '土火', '瑪瑙', '休閒,約會', NULL, '這條手串主要由棕色系和橘紅色系構成，棕色屬於土，代表穩定、踏實和滋養，能幫助你累積財富、增強人際關係的穩定性。而橘紅色則屬於火，象徵熱情、活力和行動力，可以提升你的氣場，讓你更有自信和感染力。土與火相生，火生土，所以這兩種顏色搭配起來，能讓你的能量更為和諧，既有穩固的基礎，又不失熱情與動力，對於需要增強行動力同時又想保持穩健的朋友來說，是非常好的選擇喔！', '"2026-02-27T20:06:12.000Z"', '"2026-02-27T20:06:12.000Z"', '{"detectedColors":[{"part":"主珠","color":"淺棕色","wuxing":"土"},{"part":"大圓珠","color":"深棕紅色","wuxing":"土"},{"part":"小圓珠","color":"橘紅色","wuxing":"火"}],"energyExplanation":"這條手串主要由棕色系和橘紅色系構成，棕色屬於土，代表穩定、踏實和滋養，能幫助你累積財富、增強人際關係的穩定性。而橘紅色則屬於火，象徵熱情、活力和行動力，可以提升你的氣場，讓你更有自信和感染力。土與火相生，火生土，所以這兩種顏色搭配起來，能讓你的能量更為和諧，既有穩固的基礎，又不失熱情與動力，對於需要增強行動力同時又想保持穩健的朋友來說，是非常好的選擇喔！","auraBoost":7,"analyzedAt":"2026-02-27T15:06:12.484Z"}', 7, 1),
(120001, 1, '酒紅色石榴石手串', 'bracelet', '酒紅色', '火', '石榴石', '休閒,約會,工作', NULL, '這條酒紅色的石榴石手串，在五行中屬於『火』的能量。火代表熱情、活力、光明，能增強個人的氣場和行動力，讓你更有自信、更有衝勁。石榴石本身也有助於活絡氣血、提升魅力，對於需要補充火能量、增強人緣或桃花運的人來說，是個很不錯的選擇喔！', '"2026-02-28T12:46:53.000Z"', '"2026-02-28T12:46:53.000Z"', '{"detectedColors":[{"part":"珠子","color":"酒紅色","wuxing":"火"}],"energyExplanation":"這條酒紅色的石榴石手串，在五行中屬於『火』的能量。火代表熱情、活力、光明，能增強個人的氣場和行動力，讓你更有自信、更有衝勁。石榴石本身也有助於活絡氣血、提升魅力，對於需要補充火能量、增強人緣或桃花運的人來說，是個很不錯的選擇喔！","auraBoost":7,"analyzedAt":"2026-02-28T07:46:53.743Z"}', 7, 1),
(150001, 1, '棕黃色虎眼石手串', 'bracelet', '棕黃色', '土', '虎眼石', '休閒,工作,約會', NULL, '這條虎眼石手串主要呈現棕黃色調，在五行中屬於「土」的能量。土代表穩定、踏實、滋養與包容。佩戴這類顏色的手串，可以幫助你增加 grounded 的感覺，提升安全感，讓思緒更清晰，也比較容易累積財富喔！虎眼石本身也有避邪、招財的寓意，是個很不錯的選擇。', '"2026-03-03T05:13:35.000Z"', '"2026-03-03T05:13:35.000Z"', '{"detectedColors":[{"part":"珠子","color":"棕黃色","wuxing":"土"},{"part":"珠子","color":"深棕色","wuxing":"土"}],"energyExplanation":"這條虎眼石手串主要呈現棕黃色調，在五行中屬於「土」的能量。土代表穩定、踏實、滋養與包容。佩戴這類顏色的手串，可以幫助你增加 grounded 的感覺，提升安全感，讓思緒更清晰，也比較容易累積財富喔！虎眼石本身也有避邪、招財的寓意，是個很不錯的選擇。","auraBoost":7,"analyzedAt":"2026-03-03T00:13:35.843Z"}', 7, 1),
(180001, 1, '白色矽膠智慧手錶', 'accessory', '白色', '金', '矽膠,金屬', '工作,休閒,運動,約會', NULL, '這款智慧手錶以白色錶帶為主，搭配金屬錶殼，整體五行屬金。金代表著清晰、效率、決斷力，也能帶來財運和貴人運。白色是純潔、簡約的象徵，有助於思緒清晰，提升專注力。金屬色澤則能強化個人的氣場，展現專業與現代感。黑色錶面雖然屬水，但作為螢幕背景，主要功能是顯示資訊，對整體五行影響較小，反而能以水的智慧來輔助金的銳利。戴著它，有助於你在工作上更有效率，思緒更清晰，同時也能展現你的品味與專業度。', '"2026-03-03T15:58:55.000Z"', '"2026-03-03T15:58:55.000Z"', '{"detectedColors":[{"part":"錶帶","color":"白色","wuxing":"金"},{"part":"錶殼","color":"銀色","wuxing":"金"},{"part":"錶面","color":"黑色","wuxing":"水"}],"energyExplanation":"這款智慧手錶以白色錶帶為主，搭配金屬錶殼，整體五行屬金。金代表著清晰、效率、決斷力，也能帶來財運和貴人運。白色是純潔、簡約的象徵，有助於思緒清晰，提升專注力。金屬色澤則能強化個人的氣場，展現專業與現代感。黑色錶面雖然屬水，但作為螢幕背景，主要功能是顯示資訊，對整體五行影響較小，反而能以水的智慧來輔助金的銳利。戴著它，有助於你在工作上更有效率，思緒更清晰，同時也能展現你的品味與專業度。","auraBoost":7,"analyzedAt":"2026-03-03T10:58:55.767Z"}', 7, 1);
